  1	import {
  2	  type FormEvent,
  3	  type FunctionComponent,
  4	  type KeyboardEventHandler,
  5	  type Ref,
  6	  useRef,
  7	} from 'react';
  8	
  9	import {
 10	  Button,
 11	  ButtonVariant,
 12	  MenuToggle,
 13	  type MenuToggleElement,
 14	  type SelectOptionProps,
 15	  TextInputGroup,
 16	  TextInputGroupMain,
 17	  TextInputGroupUtilities,
 18	} from '@patternfly/react-core';
 19	import { TimesIcon } from '@patternfly/react-icons';
 20	
 21	/**
 22	 * Props for the FilterableSelect component.
 23	 */
 24	type FilterableSelectMenuToggleProps = {
 25	  toggleRef: Ref<MenuToggleElement>;
 26	  placeholder?: string;
 27	  isOpen: boolean;
 28	  setIsOpen: (value: boolean) => void;
 29	  selectOptions: SelectOptionProps[];
 30	  inputValue: string;
 31	  setInputValue: (value: string) => void;
 32	  setSelectedValue: (value: string) => void;
 33	  filterValue: string;
 34	  setFilterValue: (value: string) => void;
 35	  focusedItemIndex: number | null;
 36	  setFocusedItemIndex: (value: number | null) => void;
 37	};
 38	
 39	const FilterableSelectMenuToggle: FunctionComponent<FilterableSelectMenuToggleProps> = ({
 40	  filterValue,
 41	  focusedItemIndex,
 42	  inputValue,
 43	  isOpen,
 44	  placeholder,
 45	  selectOptions,
 46	  setFilterValue,
 47	  setFocusedItemIndex,
 48	  setInputValue,
 49	  setIsOpen,
 50	  setSelectedValue,
 51	  toggleRef,
 52	}) => {
 53	  const textInputRef = useRef<HTMLInputElement>();
 54	
 55	  const onToggleClick = () => {
 56	    setIsOpen(!isOpen);
 57	  };
 58	
 59	  const onTextInputChange: (event: FormEvent<HTMLInputElement>, value: string) => void = (
 60	    _event,
 61	    value,
 62	  ) => {
 63	    setInputValue(value);
 64	    setFilterValue(value);
 65	  };
 66	
 67	  const handleMenuArrowKeys = (key: string) => {
 68	    let indexToFocus = null;
 69	
 70	    if (isOpen) {
 71	      if (key === 'ArrowUp') {
 72	        // When no index is set or at the first index, focus to the last, otherwise decrement focus index
 73	        if (focusedItemIndex === null || focusedItemIndex === 0) {
 74	          indexToFocus = selectOptions.length - 1;
 75	        } else {
 76	          indexToFocus = focusedItemIndex - 1;
 77	        }
 78	      }
 79	
 80	      if (key === 'ArrowDown') {
 81	        // When no index is set or at the last index, focus to the first, otherwise increment focus index
 82	        if (focusedItemIndex === null || focusedItemIndex === selectOptions.length - 1) {
 83	          indexToFocus = 0;
 84	        } else {
 85	          indexToFocus = focusedItemIndex + 1;
 86	        }
 87	      }
 88	
 89	      setFocusedItemIndex(indexToFocus);
 90	    }
 91	  };
 92	
 93	  const onInputKeyDown: KeyboardEventHandler<HTMLDivElement> = (event) => {
 94	    const enabledMenuItems = selectOptions.filter((menuItem) => !menuItem.isDisabled);
 95	    const [firstMenuItem] = enabledMenuItems;
 96	    const focusedItem = focusedItemIndex ? enabledMenuItems[focusedItemIndex] : firstMenuItem;
 97	
 98	    switch (event.key) {
 99	      // Select the first available option
100	      case 'Enter':
101	        event.preventDefault();
102	
103	        if (isOpen) {
104	          setInputValue(String(focusedItem?.itemId ?? filterValue));
105	          setSelectedValue(String(focusedItem?.itemId ?? filterValue));
106	        }
107	
108	        setIsOpen(!isOpen);
109	        setFocusedItemIndex(null);
110	
111	        break;
112	      case 'Tab':
113	      case 'Escape':
114	        setIsOpen(false);
115	        break;
116	      case 'ArrowUp':
117	      case 'ArrowDown':
118	        handleMenuArrowKeys(event.key);
119	        break;
120	      default:
121	        if (!isOpen) {
122	          setIsOpen(true);
123	        }
124	    }
125	  };
126	
127	  /**
128	   * Renders the toggle component for the dropdown.
129	   *
130	   * @param {Ref<any>} toggleRef The reference to the toggle component.
131	   * @returns {JSX.Element} The rendered toggle component.
132	   */
133	  return (
134	    <MenuToggle
135	      ref={toggleRef}
136	      variant="typeahead"
137	      onClick={onToggleClick}
138	      isExpanded={isOpen}
139	      isFullWidth
140	    >
141	      <TextInputGroup isPlain>
142	        <TextInputGroupMain
143	          spellCheck="false"
144	          value={inputValue}
145	          onClick={onToggleClick}
146	          onChange={onTextInputChange}
147	          onKeyDown={onInputKeyDown}
148	          id="typeahead-select-input"
149	          autoComplete="off"
150	          innerRef={textInputRef}
151	          placeholder={placeholder}
152	        />
153	
154	        <TextInputGroupUtilities>
155	          {Boolean(inputValue) && (
156	            <Button
157	              variant={ButtonVariant.plain}
158	              onClick={() => {
159	                setSelectedValue('');
160	                setInputValue('');
161	                setFilterValue('');
162	              }}
163	              aria-label="Clear input value"
164	            >
165	              <TimesIcon aria-hidden />
166	            </Button>
167	          )}
168	        </TextInputGroupUtilities>
169	      </TextInputGroup>
170	    </MenuToggle>
171	  );
172	};
173	
174	export default FilterableSelectMenuToggle;

